/**
 * Polymarket market registry — server-side access layer.
 *
 * pmRegistry.json is generated by `node scripts/build-pm-registry.mjs`
 * (re-run nightly / pre-deploy; new markets appear as the tournament
 * progresses). The liquidity gate is enforced twice: at build time
 * (snapshot) and at read time against live Gamma numbers — a market that
 * thins out drops off the API automatically. We never self-seed depth.
 *
 * pmRegistry.json is loaded lazily at first access via fs.readFileSync
 * (not a static import) so it is excluded from the server bundle and
 * can be regenerated at deploy time without rebuilding.
 */

import { readFileSync } from "node:fs";
import { join } from "node:path";

export interface PmRegistryMarket {
  key: string;
  category: string;
  eventSlug: string | null;
  eventTitle: string;
  outcomeLabel: string | null;
  icon: string | null;
  eventImage: string | null;
  question: string;
  conditionId: string;
  yesTokenId: string;
  noTokenId: string;
  negRisk: boolean;
  tickSize: number;
  minOrderSize: number;
  teamCode: string | null;
  teamName: string | null;
  groupId: string | null;
  endDate: string | null;
  snapshot: {
    yesPrice: string | null;
    liquidity: number;
    volume: number;
    bestBid: number;
    bestAsk: number;
  };
  acceptingOrders: boolean;
  visible: boolean;
  syncedAt: string;
}

interface Registry {
  builtAt: string;
  markets: PmRegistryMarket[];
}

// ─── Lazy-load registry (not a static import — keeps it out of the bundle) ────
let _registry: Registry | null = null;

function loadRegistry(): Registry {
  if (_registry) return _registry;
  const path = join(process.cwd(), "lib/wc2026/pmRegistry.json");
  try {
    const raw = readFileSync(path, "utf8");
    const parsed = JSON.parse(raw) as Registry;
    if (!parsed || !Array.isArray(parsed.markets)) {
      throw new Error("pmRegistry.json parsed but missing markets array");
    }
    if (parsed.markets.length === 0) {
      console.error(
        "[pm.ts] WARNING: pmRegistry.json loaded but contains 0 markets — " +
          "WC pages will render empty. Re-run `node scripts/build-pm-registry.mjs` to fix.",
      );
    }
    _registry = parsed;
    return _registry;
  } catch (err) {
    console.error("[pm.ts] FATAL: could not load pmRegistry.json — pages will render empty.", err);
    // Return empty registry so pages render gracefully instead of 500ing.
    return { builtAt: "missing", markets: [] };
  }
}

export const PM_GAMMA = "https://gamma-api.polymarket.com";
export const PM_CLOB = "https://clob.polymarket.com";
export const PM_DATA = "https://data-api.polymarket.com";

/** Liquidity gate (§3.5) — same thresholds as the build script. */
export const GATE = {
  minLiquidity: 5_000,
  minVolume: 10_000,
  maxSpread: 0.08,
} as const;

export function passesGate(m: {
  acceptingOrders: boolean;
  liquidity: number;
  volume: number;
  bestBid: number;
  bestAsk: number;
}): boolean {
  if (!m.acceptingOrders) return false;
  // Liquidity OR volume — a deep book with low traded volume is still real.
  if (m.liquidity < GATE.minLiquidity && m.volume < GATE.minVolume) return false;
  if (m.bestBid <= 0 || m.bestAsk <= 0) return false;
  if (m.bestAsk - m.bestBid > GATE.maxSpread) return false;
  return true;
}

export function registryBuiltAt(): string {
  return loadRegistry().builtAt;
}

/**
 * Total number of markets in the registry (all, including non-visible).
 * An empty registry (count=0 AND builtAt="missing") means the file is absent
 * or was built with --allow-empty. Exposed in the /api/wc/markets response so
 * monitoring can catch a silent-empty deploy.
 */
export function registryMarketCount(): number {
  return loadRegistry().markets.length;
}

/** Build-time-visible markets, optionally filtered. */
export function visibleMarkets(filter?: {
  category?: string;
  teamCode?: string;
  groupId?: string;
}): PmRegistryMarket[] {
  return loadRegistry().markets.filter((m) => {
    if (!m.visible) return false;
    if (filter?.category && m.category !== filter.category) return false;
    if (filter?.teamCode && m.teamCode !== filter.teamCode) return false;
    if (filter?.groupId && m.groupId !== filter.groupId) return false;
    return true;
  });
}

export function marketByKey(key: string): PmRegistryMarket | undefined {
  return loadRegistry().markets.find((m) => m.key === key);
}

// ─── refreshLive cache ─────────────────────────────────────────────────────────
//
// Module-level cache keyed by conditionId. Safe because Railway is configured
// with numReplicas = 1 in railway.toml. If numReplicas > 1 each replica caches
// independently — cache TTL mismatch is acceptable (stale fallback beats nothing)
// but requests will not share cache across replicas.
//
const LIVE_TTL_MS = 30_000; // 30 s

interface LiveEntry {
  data: {
    yesPrice: number | null;
    noPrice: number | null;
    volume: number;
    liquidity: number;
    bestBid: number;
    bestAsk: number;
    acceptingOrders: boolean;
  };
  fetchedAt: number;
}

const liveCache = new Map<string, LiveEntry>();

/** Gamma batch refresh for a set of conditionIds (chunked, parallel, cached 30s). */
export async function refreshLive(conditionIds: string[]): Promise<
  Map<
    string,
    {
      yesPrice: number | null;
      noPrice: number | null;
      volume: number;
      liquidity: number;
      bestBid: number;
      bestAsk: number;
      acceptingOrders: boolean;
    }
  >
> {
  const now = Date.now();
  const out = new Map<
    string,
    {
      yesPrice: number | null;
      noPrice: number | null;
      volume: number;
      liquidity: number;
      bestBid: number;
      bestAsk: number;
      acceptingOrders: boolean;
    }
  >();

  // Separate fresh (cache hit) from stale ids that need a network fetch.
  const staleIds: string[] = [];
  for (const id of conditionIds) {
    const entry = liveCache.get(id);
    if (entry && now - entry.fetchedAt < LIVE_TTL_MS) {
      out.set(id, entry.data);
    } else {
      staleIds.push(id);
    }
  }

  if (staleIds.length === 0) return out;

  // Chunk stale ids and fetch in parallel with a concurrency cap of 5.
  const CHUNK = 20;
  const CONCURRENCY = 5;
  const chunks: string[][] = [];
  for (let i = 0; i < staleIds.length; i += CHUNK) {
    chunks.push(staleIds.slice(i, i + CHUNK));
  }

  async function fetchChunk(chunk: string[]): Promise<void> {
    const qs = chunk.map((id) => `condition_ids=${id}`).join("&");
    let res: Response;
    try {
      res = await fetch(`${PM_GAMMA}/markets?${qs}`, {
        headers: { "user-agent": `${process.env.NEXT_PUBLIC_APP_NAME ?? "predfx"}/1.0` },
        cache: "no-store",
        signal: AbortSignal.timeout(10_000),
      });
    } catch {
      return; // network error — stale snapshot will serve as fallback in the caller
    }
    if (!res.ok) return;
    const markets = (await res.json()) as Array<{
      conditionId: string;
      outcomePrices?: string | string[];
      volume?: number | string;
      liquidity?: number | string;
      bestBid?: number;
      bestAsk?: number;
      acceptingOrders?: boolean;
    }>;
    const fetchedAt = Date.now();
    for (const m of markets) {
      let prices: string[] = [];
      try {
        prices = Array.isArray(m.outcomePrices)
          ? m.outcomePrices
          : JSON.parse(m.outcomePrices ?? "[]");
      } catch {
        prices = [];
      }
      const data = {
        yesPrice: prices[0] ? Number(prices[0]) : null,
        noPrice: prices[1] ? Number(prices[1]) : null,
        volume: Number(m.volume ?? 0),
        liquidity: Number(m.liquidity ?? 0),
        bestBid: Number(m.bestBid ?? 0),
        bestAsk: Number(m.bestAsk ?? 0),
        acceptingOrders: Boolean(m.acceptingOrders),
      };
      liveCache.set(m.conditionId, { data, fetchedAt });
      out.set(m.conditionId, data);
    }
  }

  // Run chunks in parallel with concurrency cap.
  for (let i = 0; i < chunks.length; i += CONCURRENCY) {
    await Promise.all(chunks.slice(i, i + CONCURRENCY).map(fetchChunk));
  }

  return out;
}
